/*  
 * Validate Documents Required
 * by Diego Tapia
 */

//Defines an object to store values
let response = {
    "CQP_SHOW_ERROR_MESSAGE" : false,
    "CQP_MESSAGE_DOCUMENT_REQUIRED" : []
}

let documents = this.CQP_ADOBE_WORKFLOW_DOCUMENTS;

if (documents != null && documents != undefined && documents != "") {
    //Get length of array and loop
    let requestsDocuments = this.CQP_ADOBE_WORKFLOW_LIST;

    //Set auxiliary array
    let aListRequerid = [];
    let aDuplicate = []
    let aRequerid =[]

    //Generates a simple array of the required documents

    documents.CQP_DEFAULT_DOCUMENTS.forEach(function(element) {
        if (element.REQUIRED) {
            aListRequerid.push(element.LABEL)
        }
    })

    documents.CQP_UPLOAD_DOCUMENTS.forEach(function(element) {
        if (element.REQUIRED) {
            aListRequerid.push(element.LABEL)
        }
    })

    //Evaluate the document loop 

    requestsDocuments.forEach(function(element, index) {
        if (requestsDocuments[index]["CQP_ADOBE_DOCUMENTS_OPTIONS"] == null || requestsDocuments[index]["CQP_ADOBE_DOCUMENTS_OPTIONS"] == undefined || requestsDocuments[index]["CQP_ADOBE_DOCUMENTS_OPTIONS"] == "") {
            response.CQP_SHOW_ERROR_MESSAGE = true;
            response.CQP_MESSAGE_DOCUMENT_REQUIRED.push("Adobe Send Document and Upload Document are required")
        } else {

            if (requestsDocuments[index]['CQP_ADOBE_WORKFLOW_DOCUMENTS_UPLOAD'] === null && requestsDocuments[index]["CQP_ADOBE_DOCUMENTS_OPTIONS"]['DOC_ID'] == null) {
                response.CQP_SHOW_ERROR_MESSAGE = true;
                response.CQP_MESSAGE_DOCUMENT_REQUIRED.push("Adobe Send Document and Upload Document are required")
            } else {
                //Validate that there are no duplicate documents
                const validateDuplicate = aDuplicate.find(aDuplicate => aDuplicate === element["CQP_ADOBE_DOCUMENTS_OPTIONS"]['LABEL']);
                if (validateDuplicate == undefined) {
                    aDuplicate.push(element['CQP_ADOBE_DOCUMENTS_OPTIONS']['LABEL']);
                    //Validates if the document is required to build a simple array
                    if(requestsDocuments[index]['CQP_ADOBE_DOCUMENTS_OPTIONS']['REQUIRED'] == true) {
                        aRequerid.push(element['CQP_ADOBE_DOCUMENTS_OPTIONS']['LABEL']);
                    }
                } else {
                    response.CQP_SHOW_ERROR_MESSAGE = true;
                    response.CQP_MESSAGE_DOCUMENT_REQUIRED.push("You may not upload 2 or more of the same document in Adobe Send Document")
                }
            }
        }
    })

    //Compare the simple array of required documents
    let missingRequired = new Array();

    missingRequired  = aListRequerid.filter(element => !aRequerid.includes(element));
    if(missingRequired.length != 0) {
        response.CQP_SHOW_ERROR_MESSAGE = true;
        var messageDocumentRequired = missingRequired.toString();
        response.CQP_MESSAGE_DOCUMENT_REQUIRED.push("You must upload " + messageDocumentRequired.replace(/,/g,", ") + " are documents required for Adobe Sign")
    }
}
response.CQP_MESSAGE_DOCUMENT_REQUIRED = [...new Set(response.CQP_MESSAGE_DOCUMENT_REQUIRED)]
return response;

if (this.CQP_VALIDATE_REQUIRED.CQP_SHOW_ERROR_MESSAGE == true || !this.CQP_VALIDATE_EXPIRATION_DATE.isValid) {
    return false
}

return true

let CQP_RENEWAL_CARGO = this.CQP_RENEWAL_CARGO

if (CQP_RENEWAL_CARGO == "YES") {
    return true
} else {
    return false
}

/*
* Calc Show request error dialog
* by Helen Callisaya
* Modified by Mateo Rada
*/
//validates if the FORTE_ERRORS.FORTE_ERROR_LOG variable has no errors
if (this.FORTE_ERROR.data.FORTE_ERROR_LOG == "" || 
    this.FORTE_ERROR.data.FORTE_ERROR_LOG == "no-error" || 
    this.FORTE_ERROR.data.FORTE_ERROR_LOG == null || 
    this.FORTE_ERROR.data.FORTE_ERROR_LOG == undefined) {
    return false;
} else {
    return true;
}

