let CQP_ADOBE_WORKFLOW_LIST_SELECT = this.CQP_ADOBE_WORKFLOW_LIST_SELECT
let filesList = []

CQP_ADOBE_WORKFLOW_DOCUMENTS.CQP_DEFAULT_DOCUMENTS.forEach(function(element) {
    filesList.push({
        CQP_ADOBE_DOCUMENTS_OPTIONS: {
            LABEL: element.LABEL,
            REQUIRED: element.REQUIRED,
            DOC_ID: element.DOC_ID,
            UPLOAD_FILE: element.UPLOAD_FILE
        }
    })
})

CQP_ADOBE_WORKFLOW_LIST_SELECT.forEach(function(element) {
    filesList.push(element)
})

return filesList

